import pytest

from pseudonymizer import Pseudonymizer, PseudonymizerError


def test_unknown_pii_type_raises_pseudonymizer_error() -> None:
    with pytest.raises(PseudonymizerError) as exc_info:
        Pseudonymizer("demo-seed", {"ssn": "government-id"})
    assert "unknown PII type" in str(exc_info.value)


def test_valid_mapping_constructs_successfully() -> None:
    pseudo = Pseudonymizer("demo-seed", {"name": "name"})
    assert pseudo.pseudonymize_value("name", "Alice") != "Alice"


def test_determinism_still_holds() -> None:
    pseudo_a = Pseudonymizer("demo-seed", {"email": "email"})
    pseudo_b = Pseudonymizer("demo-seed", {"email": "email"})
    assert pseudo_a.pseudonymize_value("email", "a@b.com") == pseudo_b.pseudonymize_value("email", "a@b.com")


def test_referential_integrity_still_holds() -> None:
    pseudo = Pseudonymizer("demo-seed", {"rate": "rate"})
    first = pseudo.pseudonymize_value("rate", "42.00")
    second = pseudo.pseudonymize_value("rate", "42.00")
    assert first == second
